settings.custom_liquid:
{%- comment -%}
NUVE STAMP — Mobile Hero Final (Psychology-optimized)
Paste into Shopify Custom Liquid. Mobile-only block.
{%- endcomment -%}

<div id="buy" style="position: relative; top: -90px;"></div>

{%- assign btn_text = 'Get Nuvé Stamp Now' -%}
{%- assign rating_text = '5/5' -%}
{%- assign rating_sub = 'Trusted by 5,000+ customers' -%}
{%- assign trust_left = '30-Day Money-Back Guarantee' -%}
{%- assign trust_right = 'Free Shipping' -%}

{%- assign sale_price = product.price -%}
{%- assign compare_price = product.compare_at_price_max -%}
{%- assign pct_off = 0 -%}
{%- assign savings = 0 -%}
{%- if compare_price > sale_price -%}
  {%- assign savings = compare_price | minus: sale_price -%}
  {%- assign pct_off = savings | times: 100.0 | divided_by: compare_price | round -%}
{%- endif -%}

<style>
  .nuve-mobile-hero{
    display:block;
    margin:12px 16px 0;
    padding:14px;
    border-radius:16px;
    background:rgba(201,183,255,0.22);
    border:1px solid rgba(201,183,255,0.45);
  }
  .nuve-mh-headline{
    margin:0 0 10px;
    font-size:28px;
    line-height:1.05;
    font-weight:900;
    color:#111;
    letter-spacing:-0.3px;
  }
  .nuve-mh-sub{
    margin:0 0 10px;
    font-size:13px;
    font-weight:700;
    color:rgba(17,17,17,.75);
  }
  .nuve-mh-stars{display:flex;align-items:center;gap:8px;line-height:1;margin:0 0 8px;}
  .nuve-mh-stars .stars{display:flex;gap:3px;}
  .nuve-mh-stars svg{width:14px;height:14px;fill:#F5A623;display:block;}
  .nuve-mh-rating{font-size:13px;font-weight:800;color:#111;white-space:nowrap;}

  .nuve-mh-price{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin:0 0 12px;line-height:1;}
  .nuve-mh-price .sale{font-size:28px;font-weight:900;color:#111;}
  .nuve-mh-price .compare{font-size:18px;font-weight:700;color:rgba(17,17,17,.45);text-decoration:line-through;}
  .nuve-mh-price .off{font-size:11px;font-weight:800;color:#111;background:#fff;border:1px solid rgba(17,17,17,.14);border-radius:9999px;padding:5px 8px;}

  .nuve-mh-save{margin:0 0 10px;font-size:12px;font-weight:800;color:#111;}
  .nuve-mh-save .pill{display:inline-block;background:#fff;border:1px solid rgba(17,17,17,.14);border-radius:999px;padding:4px 8px;}

  .nuve-mh-btn{
    width:100%;display:flex;align-items:center;justify-content:center;
    padding:14px 16px;border-radius:9999px;background:#111;color:#fff;
    text-decoration:none;font-size:16px;font-weight:900;line-height:1;
    box-shadow:0 12px 26px rgba(0,0,0,.18);
  }
  .nuve-mh-micro{
    margin:8px 0 0;
    font-size:11.5px;
    text-align:center;
    color:rgba(17,17,17,.72);
    font-weight:700;
  }

  .nuve-mh-trust{
    display:flex;justify-content:center;gap:14px;margin-top:10px;flex-wrap:wrap;
    font-size:12px;font-weight:700;color:rgba(17,17,17,.75);
  }
  .nuve-mh-trust span{display:inline-flex;align-items:center;gap:7px;white-space:nowrap;}
  .nuve-mh-trust svg{width:16px;height:16px;stroke:rgba(17,17,17,.75);fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round;}

  @media (min-width:750px){ .nuve-mobile-hero{display:none;} }
</style>

<div class="nuve-mobile-hero">
  <h2 class="nuve-mh-headline">Support Thicker, Healthier-Looking Hair — From Home</h2>
  <p class="nuve-mh-sub">5–10 min routine • 2–3x/week</p>

  <div class="nuve-mh-stars" aria-label="Rating {{ rating_text }}">
    <span class="stars" aria-hidden="true">
      {% for i in (1..5) %}
        <svg viewBox="0 0 24 24"><path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/></svg>
      {% endfor %}
    </span>
    <span class="nuve-mh-rating">{{ rating_text }}</span>
  </div>
  <p class="nuve-mh-sub">{{ rating_sub }}</p>

  <div class="nuve-mh-price" aria-label="Price">
    <span class="sale">{{ sale_price | money }}</span>
    {% if compare_price > sale_price %}
      <span class="compare">{{ compare_price | money }}</span>
      <span class="off">{{ pct_off }}% OFF</span>
    {% endif %}
  </div>

  {% if savings > 0 %}
    <p class="nuve-mh-save"><span class="pill">Save {{ savings | money }} today</span></p>
  {% endif %}

  <a class="nuve-mh-btn" href="#buy">{{ btn_text }}</a>
  <p class="nuve-mh-micro">Limited Launch Offer • Ships in 5–7 business days</p>

  <div class="nuve-mh-trust" role="list">
    <span role="listitem">
      <svg viewBox="0 0 24 24"><path d="M12 2l8 4v6c0 5-3.5 9.4-8 10-4.5-.6-8-5-8-10V6l8-4z"/><path d="M8.5 12.3l2.2 2.2 4.8-5.2"/></svg>
      {{ trust_left }}
    </span>
    <span role="listitem">
      <svg viewBox="0 0 24 24"><path d="M3 7l9-4 9 4-9 4-9-4z"/><path d="M3 7v10l9 4 9-4V7"/><path d="M12 11v10"/></svg>
      {{ trust_right }}
    </span>
  </div>
</div>

{%- comment -%} Mobile-only header {%- endcomment -%}

<style>
  .nuve-mobile-header{ display: none; }
  @media (max-width: 800px){
    .nuve-mobile-header{
      display: block;
      margin: 0px 6px 0px;
      text-align: center;
    }
    .nuve-mobile-header h4{
      margin: -0;
      font-size: 20px;
      line-height: 1.15;
      font-weight: 900;
      letter-spacing: -0.02em;
      color: #111;
    }
  }
</style>

<div class="nuve-mobile-header">
  <h4>Support Thicker, Healthier-Looking Hair — From Home</h4>
</div>

{%- comment -%}
Stars + rating + subtext (matches screenshot).
Edit the variables below to change the numbers/text.
{%- endcomment -%}

{%- assign rating_value = 5 -%}
{%- assign rating_max = 5 -%}
{%- assign rating_text = '5/5' -%}
{%- assign subtext = 'Trusted by 5,000+ customers' -%}

{%- style -%}
  .nuve-rating-wrap{
    display: inline-flex;
    flex-direction: column;
    gap: 6px;
  }
  .nuve-rating-top{
    display: inline-flex;
    align-items: center;
    gap: 8px;
  }
  .nuve-stars{
    display: inline-flex;
    gap: 4px;
    line-height: 1;
  }
  .nuve-star{
    width: 16px;
    height: 16px;
    display: inline-block;
  }
  .nuve-star svg{
    width: 100%;
    height: 100%;
    display: block;
    fill: #F5A623; /* warm gold like screenshot */
  }
  .nuve-rating-text{
    font-size: 14px;
    font-weight: 700;
    color: #111;
    line-height: 1;
  }
  .nuve-rating-subtext{
    font-size: 13px;
    font-weight: 500;
    color: #111;
    line-height: 1.2;
  }
{%- endstyle -%}

<div class="nuve-rating-wrap" aria-label="Rated {{ rating_text }}">
  <div class="nuve-rating-top">
    <div class="nuve-stars" role="img" aria-label="{{ rating_value }} out of {{ rating_max }} stars">
      {%- for i in (1..rating_max) -%}
        <span class="nuve-star">
          <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
            <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/>
          </svg>
        </span>
      {%- endfor -%}
    </div>

    <span class="nuve-rating-text">{{ rating_text }}</span>
  </div>

  <div class="nuve-rating-subtext">{{ subtext }}</div>
</div>

