{%- comment -%}
Premium "Best Results Tips" card
Edit title + tips below.
{%- endcomment -%}

{%- assign title = 'Best Results Tips' -%}
{%- assign kicker = 'Recommended routine' -%}
{%- assign tips = 'Use 2-3x per week, on clean/dry scalp|Always start with the lowest setting|Pair with your favorite growth serum or oil|Take before photos to track your progress!' -%}

{%- style -%}
  .nuve-tips-wrap{
    --ink: #0f172a;
    --muted: rgba(15, 23, 42, 0.72);
    --brand: #557170;
    --cream: #F1EFE7;
    --lilac: #C9B7FF;

    border-radius: 18px;
    padding: 22px 22px;
    background:
      radial-gradient(900px 260px at 15% 0%, rgba(201, 183, 255, 0.20), transparent 55%),
      radial-gradient(900px 260px at 85% 100%, rgba(85, 113, 112, 0.16), transparent 55%),
      linear-gradient(180deg, #ffffff, var(--cream));
    border: 1px solid rgba(15, 23, 42, 0.08);
    box-shadow: 0 14px 40px rgba(15, 23, 42, 0.08);
    overflow: hidden;
  }

  .nuve-tips-header{
    display: flex;
    align-items: flex-start;
    gap: 12px;
    margin-bottom: 14px;
  }

  .nuve-tips-icon{
    width: 42px;
    height: 42px;
    border-radius: 14px;
    background: rgba(85, 113, 112, 0.10);
    border: 1px solid rgba(85, 113, 112, 0.18);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex: 0 0 auto;
  }
  .nuve-tips-icon svg{
    width: 22px;
    height: 22px;
    stroke: var(--brand);
    fill: none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-tips-kicker{
    display: inline-flex;
    align-items: center;
    gap: 8px;
    font-size: 12px;
    font-weight: 700;
    color: var(--brand);
    margin-bottom: 6px;
  }
  .nuve-tips-pill{
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 6px 10px;
    border-radius: 9999px;
    background: rgba(201, 183, 255, 0.18);
    border: 1px solid rgba(201, 183, 255, 0.35);
    color: var(--ink);
    font-size: 11px;
    font-weight: 700;
    line-height: 1;
  }

  .nuve-tips-title{
    font-size: 22px;
    font-weight: 800;
    color: var(--ink);
    line-height: 1.15;
    margin: 0;
  }

  .nuve-tips-grid{
    display: grid;
    grid-template-columns: 1fr;
    gap: 10px;
    margin-top: 14px;
  }

  .nuve-tip{
    display: grid;
    grid-template-columns: 26px 1fr;
    gap: 12px;
    align-items: flex-start;
    padding: 12px 12px;
    border-radius: 14px;
    background: rgba(255, 255, 255, 0.62);
    border: 1px solid rgba(15, 23, 42, 0.06);
    transition: transform 140ms ease, box-shadow 140ms ease, background 140ms ease;
  }

  .nuve-tip:hover{
    transform: translateY(-1px);
    box-shadow: 0 10px 24px rgba(15, 23, 42, 0.08);
    background: rgba(255, 255, 255, 0.78);
  }

  .nuve-check{
    width: 22px;
    height: 22px;
    border-radius: 9999px;
    background: rgba(85, 113, 112, 0.12);
    border: 1px solid rgba(85, 113, 112, 0.20);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin-top: 2px;
  }
  .nuve-check svg{
    width: 14px;
    height: 14px;
    stroke: var(--brand);
    fill: none;
    stroke-width: 2.5;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  .nuve-tip-text{
    font-size: 14px;
    font-weight: 600;
    color: var(--ink);
    line-height: 1.35;
  }

  /* Optional: 2-column on larger screens */
  @media (min-width: 750px){
    .nuve-tips-wrap{ padding: 26px 26px; }
    .nuve-tips-grid{ grid-template-columns: 1fr 1fr; }
    .nuve-tips-title{ font-size: 24px; }
  }
{%- endstyle -%}

<div class="nuve-tips-wrap">
  <div class="nuve-tips-header">
    <div class="nuve-tips-icon" aria-hidden="true">
      <!-- sparkle/idea icon -->
      <svg viewBox="0 0 24 24">
        <path d="M12 2l1.2 3.8L17 7l-3.8 1.2L12 12l-1.2-3.8L7 7l3.8-1.2L12 2z"/>
        <path d="M5 13l.8 2.6L8 16l-2.2.7L5 19l-.8-2.3L2 16l2.2-.4L5 13z"/>
        <path d="M18 13l.8 2.6L21 16l-2.2.7L18 19l-.8-2.3L15 16l2.2-.4L18 13z"/>
      </svg>
    </div>

    <div>
      <div class="nuve-tips-kicker">
        <span class="nuve-tips-pill">{{ kicker }}</span>
      </div>
      <h3 class="nuve-tips-title">{{ title }}</h3>
    </div>
  </div>

  <div class="nuve-tips-grid" role="list">
    {%- assign tip_items = tips | split: '|' -%}
    {%- for t in tip_items -%}
      <div class="nuve-tip" role="listitem">
        <span class="nuve-check" aria-hidden="true">
          <svg viewBox="0 0 24 24">
            <path d="M20 6L9 17l-5-5"/>
          </svg>
        </span>
        <div class="nuve-tip-text">{{ t }}</div>
      </div>
    {%- endfor -%}
  </div>
</div>

{%- comment -%}
NUVE STAMP — Why This Approach Works (Prettier Version)
Paste into a Shopify "Custom liquid" block on PDP.
Recommended placement: below "How it works", above FAQ/reviews.
{%- endcomment -%}

{%- style -%}
.nuve-why{
--bg:#ffffff;
--text:#111827;
--muted:#4b5563;
--line:#e8eaf0;
--accent:#111111;
--soft1:#f8fafc;
--soft2:#f3f4f6;

margin: 26px 0;
border: 1px solid var(--line);
border-radius: 18px;
background: linear-gradient(180deg, var(--soft1) 0%, #fff 30%);
overflow: hidden;
}
.nuve-why__inner{
padding: 20px;
}
.nuve-why__kicker{
display:inline-block;
margin:0 0 10px;
padding:6px 10px;
border-radius:999px;
font-size:11px;
font-weight:700;
letter-spacing:.8px;
text-transform:uppercase;
color:#374151;
background:#eef2f7;
border:1px solid #e5e7eb;
}
.nuve-why__title{
margin:0 0 10px;
font-size:28px;
line-height:1.15;
color:var(--text);
font-weight:800;
}
.nuve-why__sub{
margin:0 0 16px;
font-size:15px;
line-height:1.6;
color:#1f2937;
max-width: 70ch;
}

.nuve-why__grid{
display:grid;
grid-template-columns:1fr 1fr;
gap:10px;
margin: 0 0 14px;
}
.nuve-why__card{
display:flex;
gap:10px;
align-items:flex-start;
border:1px solid var(--line);
background:var(--bg);
border-radius:12px;
padding:12px;
}
.nuve-why__icon{
width:30px;
height:30px;
border-radius:999px;
display:flex;
align-items:center;
justify-content:center;
font-size:15px;
background:var(--soft2);
border:1px solid #e5e7eb;
flex:0 0 30px;
}
.nuve-why__card h3{
margin:0 0 4px;
