{%- comment -%}
Nuvé CTA Section (all-in-one)
- Lilac background panel
- Headline + subcopy
- Button (either scroll-to-buy OR real Add to Cart)
- Guarantee line

How to use:
1) Place this section anywhere on the PRODUCT template.
2) Ensure you have <div id="buy"> anchor near your main purchase module if using scroll mode.
3) Set button_mode to 'scroll' or 'atc'
{%- endcomment -%}

{%- assign heading = 'Ready to Upgrade Your Hair Routine?' -%}
{%- assign subtext = 'Start your at-home routine for thicker, healthier-looking hair — no clinic visits required.' -%}
{%- assign button_text = 'Get Nuvé Stamp Now' -%}
{%- assign guarantee_text = '30-Day Money-Back Guarantee' -%}

{%- comment -%}
button_mode:
- 'scroll' = button links to #buy
- 'atc' = button adds to cart (product page only)
{%- endcomment -%}
{%- assign button_mode = 'scroll' -%}

{%- style -%}
  .nuve-cta-section{
    --ink:#0f172a;
    --muted:rgba(15,23,42,.72);
    --lilac:#d9cffc; /* close to screenshot */
    --lilac-2:#c9b7ff;
    --shadow: 0 18px 55px rgba(15,23,42,.10);

    max-width: 1100px;
    margin: 0 auto;
    padding: 28px 18px;
  }

  .nuve-cta-panel{
    background: var(--lilac);
    border-radius: 22px;
    padding: 42px 22px;
    text-align: center;
    box-shadow: var(--shadow);
    border: 1px solid rgba(15,23,42,.08);
    position: relative;
    overflow: hidden;
  }

  /* subtle glow accents */
  .nuve-cta-panel:before{
    content:"";
    position:absolute;
    inset:-200px -200px auto auto;
    width: 420px;
    height: 420px;
    background: radial-gradient(circle, rgba(201,183,255,.55), rgba(201,183,255,0) 60%);
    transform: translate(20%, -15%);
    pointer-events:none;
  }
  .nuve-cta-panel:after{
    content:"";
    position:absolute;
    inset:auto auto -220px -220px;
    width: 520px;
    height: 520px;
    background: radial-gradient(circle, rgba(255,255,255,.45), rgba(255,255,255,0) 60%);
    pointer-events:none;
  }

  .nuve-cta-inner{
    position: relative;
    z-index: 1;
    max-width: 860px;
    margin: 0 auto;
  }

  .nuve-cta-title{
    font-size: 44px;
    font-weight: 900;
    letter-spacing: -0.03em;
    color: #0b0f1a;
    margin: 0 0 14px;
    line-height: 1.05;
  }

  .nuve-cta-sub{
    font-size: 16px;
    font-weight: 600;
    color: rgba(11,15,26,.78);
    margin: 0 auto 22px;
    line-height: 1.55;
    max-width: 720px;
  }

  .nuve-cta-btn{
    display:inline-flex;
    align-items:center;
    justify-content:center;
    padding: 16px 28px;
    border-radius: 9999px;
    background: #0b0b0c;
    color: #fff;
    font-size: 15px;
    font-weight: 900;
    text-decoration: none;
    border: 0;
    cursor: pointer;
    box-shadow: 0 14px 34px rgba(0,0,0,.22);
    transition: transform .14s ease, box-shadow .14s ease, opacity .14s ease;
    min-width: 260px;
  }
  .nuve-cta-btn:hover{ transform: translateY(-1px); box-shadow: 0 18px 42px rgba(0,0,0,.26); }
  .nuve-cta-btn:active{ transform: translateY(0); opacity:.92; }
  .nuve-cta-btn[disabled]{ opacity:.6; cursor:not-allowed; transform:none; box-shadow:none; }

  .nuve-cta-guarantee{
  margin-top: 16px;
  display: flex;            /* <- key change */
  justify-content: center;  /* center it */
  align-items: center;
  gap: 10px;
  width: 100%;              /* forces it onto its own line */
  font-size: 13px;
  font-weight: 700;
  color: rgba(11,15,26,.78);
}

  .nuve-cta-ico{
    width: 18px;
    height: 18px;
    display:inline-block;
  }
  .nuve-cta-ico svg{
    width: 100%;
    height: 100%;
    display:block;
    stroke: rgba(11,15,26,.78);
    fill:none;
    stroke-width: 2;
    stroke-linecap: round;
    stroke-linejoin: round;
  }

  /* Responsive */
  @media (max-width: 749px){
    .nuve-cta-panel{ padding: 34px 18px; }
    .nuve-cta-title{ font-size: 34px; }
    .nuve-cta-sub{ font-size: 15px; }
    .nuve-cta-btn{ min-width: 220px; }
  }
{%- endstyle -%}

<section class="nuve-cta-section">
  <div class="nuve-cta-panel">
    <div class="nuve-cta-inner">
      <h2 class="nuve-cta-title">{{ heading }}</h2>
      <p class="nuve-cta-sub">{{ subtext }}</p>

      {%- if button_mode == 'scroll' -%}
        <a class="nuve-cta-btn" href="#buy">{{ button_text }}</a>

      {%- elsif button_mode == 'atc' and product -%}
        {%- assign v = product.selected_or_first_available_variant -%}
        <product-form>
          {% form 'product', product, id: 'nuveInlineCTA', novalidate: 'novalidate' %}
            <input type="hidden" name="id" value="{{ v.id }}">
            <input type="hidden" name="quantity" value="1">
            <button class="nuve-cta-btn" type="submit" name="add" {% unless v.available %}disabled{% endunless %}>
              {% if v.available %}{{ button_text }}{% else %}Sold out{% endif %}
            </button>
          {% endform %}
        </product-form>
      {%- else -%}
        <a class="nuve-cta-btn" href="#buy">{{ button_text }}</a>
      {%- endif -%}

      <div class="nuve-cta-guarantee">
        <span class="nuve-cta-ico" aria-hidden="true">
          <!-- shield check -->
          <svg viewBox="0 0 24 24">
            <path d="M12 2l8 4v6c0 5-3.5 9.4-8 10-4.5-.6-8-5-8-10V6l8-4z"/>
            <path d="M8.5 12.3l2.2 2.2 4.8-5.2"/>
          </svg>
        </span>
        <span>{{ guarantee_text }}</span>
      </div>
    </div>
  </div>
</section>

{%- comment -%}
If you use button_mode = 'scroll', make sure you have this anchor above your buy box:
<div id="buy" style="position: relative; top: -90px;"></div>
{%- endcomment -%}
